class Solution:
    def validIPAddress(self, queryIP):
        def is_v4(q):
            parts = q.split('.')
            if len(parts) != 4:
                return False
            for p in parts:
                if not p.isdigit():
                    return False
                if len(p) > 1 and p[0] == '0':
                    return False
                if len(p) == 0 or len(p) > 3:
                    return False
                if int(p) > 255:
                    return False
            return True
        def is_v6(q):
            parts = q.split(':')
            if len(parts) != 8:
                return False
            hexd = set('0123456789abcdefABCDEF')
            for p in parts:
                if not (1 <= len(p) <= 4):
                    return False
                for c in p:
                    if c not in hexd:
                        return False
            return True
        if is_v4(queryIP):
            return 'IPv4'
        if is_v6(queryIP):
            return 'IPv6'
        return 'Neither'

