import re


class Solution:
    def validIPAddress(self, queryIP):
        v4 = re.compile(r'^(25[0-5]|2[0-4]\d|1\d\d|[1-9]\d|\d)(\.(25[0-5]|2[0-4]\d|1\d\d|[1-9]\d|\d)){3}$')
        v6 = re.compile(r'^[0-9a-fA-F]{1,4}(:[0-9a-fA-F]{1,4}){7}$')
        if v4.match(queryIP):
            return 'IPv4'
        if v6.match(queryIP):
            return 'IPv6'
        return 'Neither'

